Can you review this React component? I feel like it's re-rendering too much but I'm not sure why.

```jsx
import { useState, useEffect } from 'react';

function OrderSummary({ items, taxRate }) {
  const [subtotal, setSubtotal] = useState(0);
  const [tax, setTax] = useState(0);
  const [total, setTotal] = useState(0);

  useEffect(() => {
    const newSubtotal = items.reduce((sum, item) => sum + item.price * item.qty, 0);
    setSubtotal(newSubtotal);
  }, [items]);

  useEffect(() => {
    setTax(subtotal * taxRate);
  }, [subtotal, taxRate]);

  useEffect(() => {
    setTotal(subtotal + tax);
  }, [subtotal, tax]);

  return (
    <div>
      <h2>Order Summary</h2>
      {items.map(item => (
        <div key={item.id}>
          {item.name} x{item.qty} — ${(item.price * item.qty).toFixed(2)}
        </div>
      ))}
      <hr />
      <p>Subtotal: ${subtotal.toFixed(2)}</p>
      <p>Tax: ${tax.toFixed(2)}</p>
      <p>Total: ${total.toFixed(2)}</p>
    </div>
  );
}

export default OrderSummary;
```

