  return (
    <ul>
      {results.map(r => (
        <li key={r.id}>{r.title}</li>
      ))}
    </ul>
  );
}

export default SearchResults;
```

I have a chat app where switching conversations should clear the draft text and close the emoji picker. I'm using useEffect to reset state when conversationId changes. Is there a better way?

```jsx
import { useState, useEffect } from 'react';

function ChatPanel({ conversationId, messages }) {
  const [draft, setDraft] = useState('');
  const [showEmojiPicker, setShowEmojiPicker] = useState(false);

  useEffect(() => {
    setDraft('');
    setShowEmojiPicker(false);
  }, [conversationId]);

  return (
    <div>
      <div className="messages">
        {messages.map(m => <Message key={m.id} message={m} />)}
      </div>
      <textarea value={draft} onChange={e => setDraft(e.target.value)} />
      {showEmojiPicker && <EmojiPicker onSelect={emoji => setDraft(d => d + emoji)} />}
      <button onClick={() => setShowEmojiPicker(!showEmojiPicker)}>😀</button>
    </div>
  );
}
```

