I have a UserProfile component that fetches user data and passes it up to the parent Layout via an onUserLoaded callback in a useEffect. My teammate says this is an anti-pattern but I don't understand why — how else would the parent get the data?

```jsx
import { useState, useEffect } from 'react';

function UserProfile({ userId, onUserLoaded }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetch(`/api/users/${userId}`)
      .then(res => res.json())
      .then(data => setUser(data));
  }, [userId]);

  useEffect(() => {
    if (user) {
      onUserLoaded(user);
    }
  }, [user, onUserLoaded]);

  if (!user) return <p>Loading...</p>;

  return (
    <div>
      <h2>{user.name}</h2>
      <p>{user.email}</p>
    </div>
  );
}
```
